export const TECHNIQUES = Object.freeze(Object.fromEntries(TECHNIQUE_LIST.map((entry) => [entry.id, entry])));

export function getTechnique(id) {
  return TECHNIQUES[id] ?? null;
}

export function getTechniques(ids = []) {
  return ids.map((id) => getTechnique(id)).filter(Boolean);
}
